Here is how game engines use bitwise operations to set, clear, and check boolean states in a single integer variable:

```cpp
// Define binary flags
constexpr uint8_t STATE_NONE        = 0;
constexpr uint8_t STATE_CROUCHING    = 1 << 0; // 0001
constexpr uint8_t STATE_POISONED      = 1 << 1; // 0010
constexpr uint8_t STATE_INVULNERABLE  = 1 << 2; // 0100

uint8_t PlayerState = STATE_NONE;

// Set state using bitwise OR
PlayerState |= STATE_CROUCHING;

// Check state using bitwise AND
bool isInvulnerable = (PlayerState & STATE_INVULNERABLE) != 0;

// Clear state using bitwise AND & NOT
PlayerState &= ~STATE_CROUCHING;
```
